import heapq
class Solution:
    def minCost(self, maxTime, edges, passingFees):
        n = len(passingFees)
        INF = float('inf')
        adj = [[] for _ in range(n)]
        for x, y, t in edges:
            adj[x].append((y, t))
            adj[y].append((x, t))
        best_time = [INF] * n
        pq = [(passingFees[0], 0, 0)]
        best_time[0] = 0
        while pq:
            cost, time, u = heapq.heappop(pq)
            if u == n - 1:
                return cost
            for v, w in adj[u]:
                nt = time + w
                if nt <= maxTime and nt < best_time[v]:
                    best_time[v] = nt
                    heapq.heappush(pq, (cost + passingFees[v], nt, v))
        return -1

