var minCost = function(maxTime, edges, passingFees) {
    const n = passingFees.length;
    const INF = Infinity;
    const adj = Array.from({length: n}, () => []);
    for (const [x, y, t] of edges) {
        adj[x].push([y, t]);
        adj[y].push([x, t]);
    }
    const bestTime = new Array(n).fill(INF);
    bestTime[0] = 0;
    const pq = [[passingFees[0], 0, 0]];
    const cmp = (a, b) => a[0] - b[0];
    while (pq.length) {
        pq.sort(cmp);
        const [cost, time, u] = pq.shift();
        if (u === n - 1) return cost;
        for (const [v, w] of adj[u]) {
            const nt = time + w;
            if (nt <= maxTime && nt < bestTime[v]) {
                bestTime[v] = nt;
                pq.push([cost + passingFees[v], nt, v]);
            }
        }
    }
    return -1;
};
